# Enforce MFA for all human users via a service control policy (SCP)
# Applied at the AWS Organizations level — affects all accounts
aws organizations create-policy \n  --name RequireMFA \n  --type SERVICE_CONTROL_POLICY \n  --description 'Deny all actions if MFA not present' \n  --content '{
    "Version": "2012-10-17",
    "Statement": [{
      "Sid": "DenyWithoutMFA",
      "Effect": "Deny",
      "NotAction": [
        "iam:CreateVirtualMFADevice",
        "iam:EnableMFADevice",
        "iam:GetUser",
        "sts:GetSessionToken"
      ],
      "Resource": "*",
      "Condition": {
        "BoolIfExists": {
          "aws:MultiFactorAuthPresent": "false"
        }
      }
    }]
  }'

# Create a customer-managed KMS key for S3 encryption
aws kms create-key \n  --description 'S3 encryption key for customer PII data' \n  --key-usage ENCRYPT_DECRYPT \n  --origin AWS_KMS

# Create an alias for readability
aws kms create-alias \n  --alias-name alias/pii-s3-key \n  --target-key-id arn:aws:kms:us-east-1:123456789012:key/abc12345

# Apply server-side encryption with the CMK to an S3 bucket
aws s3api put-bucket-encryption \n  --bucket my-pii-bucket \n  --server-side-encryption-configuration '{
    "Rules": [{
      "ApplyServerSideEncryptionByDefault": {
        "SSEAlgorithm": "aws:kms",
        "KMSMasterKeyID": "alias/pii-s3-key"
      },
      "BucketKeyEnabled": true
    }]
  }'

# Enable GuardDuty in all regions via AWS Organizations
aws guardduty create-detector \n  --enable \n  --data-sources '{
    "S3Logs": { "Enable": true },
    "Kubernetes": { "AuditLogs": { "Enable": true } },
    "MalwareProtection": { "ScanEc2InstanceWithFindings": { "EbsVolumes": true } }
  }'

# List high-severity findings
aws guardduty list-findings \n  --detector-id  \n  --finding-criteria '{
    "Criterion": {
      "severity": { "Gte": 7 }
    }
  }'

# Create a WAF Web ACL with AWS managed rule groups
aws wafv2 create-web-acl \
  --name my-app-waf \
  --scope REGIONAL \
  --default-action Allow={} \
  --rules '[
    {
      "Name": "AWSManagedRulesCommonRuleSet",
      "Priority": 1,
      "OverrideAction": { "None": {} },
      "Statement": {
        "ManagedRuleGroupStatement": {
          "VendorName": "AWS",
          "Name": "AWSManagedRulesCommonRuleSet"
        }
      },
      "VisibilityConfig": {
        "SampledRequestsEnabled": true,
        "CloudWatchMetricsEnabled": true,
        "MetricName": "CommonRuleSet"
      }
    }
  ]' \
  --visibility-config SampledRequestsEnabled=true,CloudWatchMetricsEnabled=true,MetricName=my-app-waf \
  --region us-east-1

# S3 bucket policy: only allow access from a specific VPC endpoint
# Any request arriving via the public internet is denied
aws s3api put-bucket-policy \
  --bucket my-private-data-bucket \
  --policy '{
    "Version": "2012-10-17",
    "Statement": [{
      "Sid": "DenyNonVPCe",
      "Effect": "Deny",
      "Principal": "*",
      "Action": "s3:*",
      "Resource": [
        "arn:aws:s3:::my-private-data-bucket",
        "arn:aws:s3:::my-private-data-bucket/*"
      ],
      "Condition": {
        "StringNotEquals": {
          "aws:SourceVpce": "vpce-0abc123456789"
        }
      }
    }]
  }'
